window.I18N_TRANSLATIONS = {
	"ro": {
		"meta.title": "Cum am construit Crayo în 3 zile: de la Claude Design la primul străin plătitor - Voic Andrei",
		"meta.description": "Cum am construit Crayo, un SaaS care transformă pozele în PDF-uri cu cărți de colorat generate de AI, în trei zile. De la un prototip Claude Design la un produs live cu Stripe și primii mei 2 euro de la un complet necunoscut.",
		"title": "Cum am construit Crayo în 3 zile: de la Claude Design la primul străin plătitor",
		"date": "<time datetime=\"2026-05-17\">17 mai 2026</time>",
		"h.euros": "Doi euro de la un străin",
		"p.euros1": "La câteva zile după ce am lansat discret <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a>, telefonul mi-a vibrat cu o notificare de la Stripe. Un complet necunoscut, cineva pe care nu l-am întâlnit niciodată și căruia nu i-am vândut nimic direct, îmi plătise aproximativ 2 euro pentru o carte de colorat personalizată, făcută din propriile lui poze.",
		"p.euros2": "Este o sumă minusculă, dar m-a făcut sincer fericit. Cineva s-a uitat la produsul meu, a decis că merită banii lui și a plătit pentru el. Asta a fost partea care a contat pentru mine.",
		"h.what": "Ce este Crayo",
		"p.what1": "<strong>Crayo</strong> este un mic SaaS în limba română care transformă orice poză într-un PDF cu o carte de colorat personalizată, generată de AI. Încarci poze cu copilul tău, cu câinele tău, cu un moment în familie, orice vrei. Plătești prin Stripe. Primești un PDF imprimabil cu pagini de colorat curate, potrivite pentru copii, generate din imaginile tale. Tot produsul este în română, cu prețuri în lei, adresat părinților din România.",
		"p.what2": "Prețul de astăzi este intenționat simplu: până la 20 de poze pentru 9,90 lei. Nu optimizez pentru marjă în această etapă. Optimizez pentru cel mai mic preț posibil care încă necesită o tranzacție Stripe reală, astfel încât primul client să fie un semnal comercial autentic și nu o favoare din partea cuiva care mă cunoaște.",
		"h.why": "De ce l-am construit, totuși",
		"p.why1": "Sincer, am început Crayo ca să văd ce poate face Claude Design. Anthropic Labs l-a lansat în aprilie 2026 și voiam un proiect real, de la cap la coadă, pe care să îl testez. Planul era să petrec o după-amiază prototipând ideea, să mă uit la rezultat și să merg mai departe.",
		"p.why2": "Odată ce am văzut ce a ieșit din acea după-amiază, am decis să îl lansez în schimb. Mi-am dat și o provocare personală: să construiesc un SaaS care chiar să obțină cel puțin un client plătitor din afara cercului meu. Nu prieteni, nu familie, nu colegi generoși. Un străin adevărat care plătește bani reali pentru un produs real. Acea provocare este ceea ce m-a făcut să trec dincolo de prototip și să îl lansez cu adevărat.",
		"h.threedays": "Trei zile, de la cap la coadă",
		"p.threedays1": "Întreaga construcție tehnică a durat trei zile. Domeniu, frontend, backend, pipeline de generare a imaginilor, plăți, deployment, analytics. Cronologia nu înseamnă că eu sunt rapid. Cronologia este fluxul de lucru.",
		"h.phase1": "Faza 1: Prototipare în Claude Design",
		"p.phase1a": "Am început în <a href=\"https://www.anthropic.com/news/claude-design-anthropic-labs\" target=\"_blank\">Claude Design</a>, instrumentul de prototipare vizuală pe care Anthropic Labs l-a lansat în aprilie 2026. Premisa este simplă. Descrii un produs în limbaj natural și Claude construiește o primă versiune a interfeței. Apoi rafinezi prin conversație, comentarii inline, editări directe și slidere personalizate. Este alimentat de Claude Opus 4.7 și, esențial, rezultatele sunt concepute pentru a fi predate către Claude Code pentru o implementare reală.",
		"p.phase1b": "Am petrecut prima parte a primei zile acolo. I-am spus lui Claude Design cine era clientul, un părinte din România care vrea o carte de colorat personalizată făcută din pozele copilului său, și l-am urmărit producând o pagină de destinație reală, pe care se poate da click, în română: hero, înainte/după, niveluri de preț, FAQ, footer. Am rafinat layoutul, am strâns textul, am ales paleta și am ajustat spațierea. Am ajuns la o pagină de destinație pe care mi-ar fi fost rușine să o construiesc manual în același interval de timp.",
		"p.phase1c": "Până la finalul acelei sesiuni nu aveam o specificație de o pagină. Aveam un prototip de frontend funcțional, șlefuit, cu o viziune clară, inclusiv identitatea vizuală a brandului, care stătea în Claude Design și era gata să fie predat.",
		"h.phase2": "Faza 2: Predarea către Claude Code",
		"p.phase2a": "Apoi l-am predat lui <strong>Claude Code</strong> și l-am lăsat să construiască restul: aducerea prototipului din Claude Design într-un proiect real Vite + React, conectarea încărcării de poze, construirea backendului Hono, integrarea Vertex AI Gemini pentru generarea imaginilor, conectarea Stripe Checkout, configurarea Cloud Run, Firestore, regulile de ciclu de viață GCS, botul de notificări Telegram, deployment-ul prin GitHub Actions către Cloudflare Pages și fluxul de consimțământ pentru analytics.",
		"p.phase2b": "De acolo a fost o buclă. Descriam următoarea bucată de comportament, Claude Code o implementa, eu o testam, iteram. Construcția a decurs ca o secvență de tichete bine delimitate, fiecare suficient de mic încât să poată fi verificat înainte de a merge mai departe. Până la finalul celei de-a treia zile aveam un produs deployat, care accepta plăți, pe un domeniu personalizat.",
		"p.phase2c": "Predarea în sine a fost partea de care nu mă așteptam să mă bucur atât de mult. Claude Design a produs suprafața pe care o vede clientul, Claude Code a produs tot ce este în spatele ei, iar cele două instrumente s-au îmbinat ca un singur flux de lucru continuu, nu ca două produse separate lipite la cusături.",
		"h.stack": "Stack-ul",
		"p.stack1": "Nimic de aici nu este inovator. Am ales servicii gestionate oriunde am putut.",
		"li.frontend": "<strong>Frontend</strong>: Vite + React 18, deployat pe <strong>Cloudflare Pages</strong> cu auto-deploy din GitHub la fiecare push pe <code>main</code>. Zero infrastructură de gestionat, push-urile ajung live în mai puțin de un minut.",
		"li.backend": "<strong>Backend</strong>: <strong>Hono</strong> pe Node 20, TypeScript cu strict mode activat, deployat pe <strong>Google Cloud Run</strong> în regiunea <code>europe-west3</code> (Frankfurt). Aproape de utilizatorii din România, scalează la zero, costă aproape nimic cât timp traficul este mic.",
		"li.database": "<strong>Bază de date</strong>: <strong>Firestore</strong>. O colecție per tip logic. Fără migrări, fără fișiere de schemă, fără cluster de bază de date de operat.",
		"li.storage": "<strong>Stocare</strong>: <strong>Google Cloud Storage</strong>. Două bucket-uri, unul pentru încărcările primite de la utilizatori cu un TTL strict de 72 de ore, unul pentru comenzile finalizate.",
		"li.imagegen": "<strong>Generare de imagini</strong>: <strong>Vertex AI Gemini</strong> (cel mai recent model image-preview) ca pipeline principal, cu un model de imagine OpenAI conectat ca rezervă pentru reziliență.",
		"li.payments": "<strong>Plăți</strong>: <strong>Stripe Checkout</strong>. Datele cardului nu ajung niciodată pe serverele mele. Stripe gestionează întreaga suprafață de plată și eu doar primesc un webhook care îmi spune că o comandă este plătită.",
		"li.notifications": "<strong>Notificări</strong>: un bot Telegram îmi sună telefonul de fiecare dată când se întâmplă ceva interesant, cum ar fi plasarea unei comenzi, finalizarea unei generări sau declanșarea unui webhook. Funcționează ca un dashboard de operațiuni extrem de simplu.",
		"li.analytics": "<strong>Analytics</strong>: Cloudflare Web Analytics (fără cookie-uri, prietenos cu GDPR), cu Meta Pixel, CAPI și GA4 pregătite în spatele unui banner de cookie-uri cu Consent Mode v2 pentru momentul când traficul o va justifica.",
		"p.stack2": "Niciuna dintre aceste alegeri nu este ingenioasă. Sunt deliberat plictisitoare, pentru că infrastructura plictisitoare este genul care mă lasă în pace.",
		"h.security": "Securitate, pentru că produsul procesează poze cu copii",
		"p.security1": "Despre această parte vreau să fiu explicit. Cazul de utilizare principal pentru Crayo sunt părinții care încarcă poze cu copiii lor. Unele dintre acele poze sunt amintiri de familie pe care nimeni altcineva nu ar trebui să le vadă vreodată. Am tratat asta ca pe o cerință obligatorie încă de la prima conversație de design, nu ca pe o funcție pe care aș adăuga-o mai târziu.",
		"p.security2": "Iată cum arată asta concret:",
		"li.sec.payments": "<strong>Plățile sunt complet în afara platformei.</strong> Tot checkout-ul se întâmplă pe Stripe. Numere de card, detalii de facturare, CVV. Nimic din toate astea nu ajunge vreodată pe un server, log sau bază de date Crayo. Nu pot să scurg date pe care nu le-am avut niciodată.",
		"li.sec.autodelete": "<strong>Pozele încărcate se șterg automat.</strong> Încărcările utilizatorilor ajung într-un bucket Cloud Storage cu o <strong>regulă de ciclu de viață de 72 de ore</strong>. După acea fereastră, Google însuși le elimină. Nu este necesară nicio acțiune de administrare și nu am cum să uit.",
		"li.sec.notrain": "<strong>Pozele nu sunt folosite pentru a antrena nimic.</strong> Endpoint-urile de imagine Vertex AI pe care le folosesc nu sunt pipeline-uri de antrenare. Poza unui copil intră, o pagină de colorat iese, iar imaginea sursă este eliminată pe cronometrul de 72 de ore.",
		"li.sec.secrets": "<strong>Secretele stau în Google Secret Manager.</strong> Chei Stripe, credențiale API, secrete de semnare a webhook-urilor. Niciunul dintre ele nu este în repo, niciunul nu este în fișiere de mediu comise undeva, iar serviciul Cloud Run le leagă la runtime prin <code>--set-secrets</code>.",
		"li.sec.https": "<strong>Doar HTTPS, peste tot.</strong> Cloudflare în fața site-ului static, certificate gestionate de Google în fața Cloud Run.",
		"li.sec.gdpr": "<strong>Consimțământ GDPR înainte de orice urmărire.</strong> Bannerul de consimțământ blochează Meta Pixel, GA4 și orice tag-uri neesențiale până când utilizatorul își dă acordul. Cloudflare Web Analytics este singurul lucru care rulează fără consimțământ, pentru că este fără cookie-uri și agregat.",
		"p.security3": "Nimic din toate astea nu este exotic. Este versiunea de \"implicit sigur\" cu care pot trăi, având în vedere ce încarcă oamenii.",
		"h.headline": "De ce cele trei zile sunt titlul, nu tehnologia",
		"p.headline1": "Lucrul interesant la Crayo nu este stack-ul. Stack-ul este oricare ar fi stack-ul. Lucrul interesant este că prețul de a ajunge de la \"am o idee la cafeaua de dimineață\" la \"un străin m-a plătit pentru ea\" s-a prăbușit.",
		"p.headline2": "Cu câțiva ani în urmă, această construcție ar fi fost un proiect de câteva săptămâni. Aș fi petrecut zile cu autentificarea, zile cu pipeline-urile de generare a imaginilor, zile luptându-mă cu o integrare de plăți. Astăzi blocajul s-a mutat complet de la scrierea codului către lucrurile pe care AI nu le poate face în locul meu: să decid ce să construiesc, să vorbesc cu utilizatori reali, să înțeleg piața și să îmi asum riscul legal de a pune o afacere în lume.",
		"h.next": "Ce urmează",
		"p.next1": "Crayo este la începutul vieții sale. Chiar acum sunt în faza de achiziție: rulez o mică campanie Meta Ads, urmăresc analytics-ul, fac A/B testing pe pagina de destinație și citesc fiecare bucată de feedback pe care o primesc de la clienți reali. Următoarea bornă nu este o funcție mai sofisticată. Este al zecelea străin plătitor, și apoi al o sutălea.",
		"p.next2": "Ca să accelerez bucla aceea, am pus la punct o rutină Claude care rulează în fiecare zi. Trage performanța reclamelor din ziua precedentă din Meta, schițează creative noi și fie ajustează campania, fie face modificări pe site-ul crayo.ro pe baza a ceea ce vede. Sunt sincer curios să văd cum merge.",
		"p.next3": "Acea primă notificare Stripe de 2 euro de la un străin este în continuare partea la care tot revin cu gândul. A făcut ca totul să pară real.",
		"p.next4": "Dacă ai copii, un câine sau o amintire pe care vrei să o transformi într-o carte de colorat, <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a> este live. Și dacă stai pe o idee întrebându-te dacă o poți lansa, cu instrumentele potrivite, trei zile sunt probabil de ajuns.",
		"h.keepreading": "Continuă să citești",
		"p.keepreading": "Continuă cu <a href=\"/blog/\">indexul blogului</a>, citește cum am <a href=\"/blog/3d-printer-caricature.html\">transformat o imprimantă 3D într-un artist caricaturist</a> sau <a href=\"/blog/ai-powered-f1-leaderboard.html\">cum am construit un clasament F1 cu AI</a>.",
		"cta.home": "Înapoi la pagina principală",
		"cta.blog": "Mai multe articole de blog",
		"cta.crayo": "Vizitează Crayo"
	},
	"de": {
		"meta.title": "Crayo in 3 Tagen gebaut: Von Claude Design zum ersten zahlenden Fremden - Voic Andrei",
		"meta.description": "Wie ich Crayo, ein SaaS, das Fotos in KI-generierte Malbuch-PDFs verwandelt, in drei Tagen gebaut habe. Von einem Claude-Design-Prototyp zu einem live geschalteten, Stripe-gestützten Produkt und meinen ersten 2 Euro von einem völlig Fremden.",
		"title": "Crayo in 3 Tagen gebaut: Von Claude Design zum ersten zahlenden Fremden",
		"date": "<time datetime=\"2026-05-17\">17. Mai 2026</time>",
		"h.euros": "Zwei Euro von einem Fremden",
		"p.euros1": "Ein paar Tage nachdem ich <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a> still gelauncht hatte, vibrierte mein Handy mit einer Stripe-Benachrichtigung. Ein völlig Fremder, jemand, den ich nie getroffen oder dem ich nie direkt etwas verkauft hatte, hatte mir etwa 2 Euro für ein personalisiertes Malbuch aus seinen eigenen Fotos bezahlt.",
		"p.euros2": "Es ist eine winzige Zahl, aber sie hat mich wirklich glücklich gemacht. Jemand hat sich mein Produkt angesehen, entschieden, dass es sein Geld wert ist, und dafür bezahlt. Das ist der Teil, der mir wichtig war.",
		"h.what": "Was Crayo ist",
		"p.what1": "<strong>Crayo</strong> ist ein kleines rumänischsprachiges SaaS, das jedes Foto in ein personalisiertes, KI-generiertes Malbuch-PDF verwandelt. Du lädst Bilder von deinem Kind, deinem Hund, einem Familienmoment hoch, was immer du willst. Du zahlst über Stripe. Du bekommst ein druckbares PDF mit sauberen, kindgerechten Malseiten, die aus deinen Bildern generiert wurden. Das gesamte Produkt ist auf Rumänisch, in Lei bepreist und richtet sich an rumänische Eltern.",
		"p.what2": "Die Preisgestaltung ist heute bewusst einfach: bis zu 20 Fotos für 9,90 Lei. Ich optimiere in dieser Phase nicht auf Marge. Ich optimiere auf den kleinstmöglichen Preis, der dennoch eine echte Stripe-Transaktion erfordert, damit der erste Kunde ein echtes kommerzielles Signal ist und kein Gefallen von jemandem, der mich kennt.",
		"h.why": "Warum ich es überhaupt gebaut habe",
		"p.why1": "Ehrlich gesagt habe ich Crayo angefangen, um zu sehen, was Claude Design kann. Anthropic Labs hat es im April 2026 veröffentlicht, und ich wollte ein echtes End-to-End-Projekt, um es auszuprobieren. Der Plan war, einen Nachmittag damit zu verbringen, die Idee zu prototypisieren, mir das Ergebnis anzusehen und weiterzuziehen.",
		"p.why2": "Sobald ich sah, was aus diesem Nachmittag herauskam, beschloss ich, es stattdessen zu launchen. Ich gab mir auch eine persönliche Herausforderung: ein SaaS zu bauen, das tatsächlich mindestens einen zahlenden Kunden von außerhalb meines Netzwerks gewinnt. Keine Freunde, keine Familie, keine großzügigen Kollegen. Ein echter Fremder, der echtes Geld für ein echtes Produkt zahlt. Diese Herausforderung hat mich dazu gebracht, über den Prototyp hinauszugehen und es tatsächlich zu launchen.",
		"h.threedays": "Drei Tage, von Anfang bis Ende",
		"p.threedays1": "Der gesamte technische Aufbau dauerte drei Tage. Domain, Frontend, Backend, Bildgenerierungs-Pipeline, Zahlungen, Deployment, Analytics. Der Zeitrahmen liegt nicht daran, dass ich schnell bin. Der Zeitrahmen ist der Workflow.",
		"h.phase1": "Phase 1: Prototyping in Claude Design",
		"p.phase1a": "Ich begann in <a href=\"https://www.anthropic.com/news/claude-design-anthropic-labs\" target=\"_blank\">Claude Design</a>, dem visuellen Prototyping-Tool, das Anthropic Labs im April 2026 veröffentlicht hat. Die Prämisse ist einfach. Du beschreibst ein Produkt in natürlicher Sprache, und Claude baut eine erste Version der Oberfläche. Anschließend verfeinerst du über Konversation, Inline-Kommentare, direkte Bearbeitungen und individuelle Slider. Es wird von Claude Opus 4.7 angetrieben, und entscheidend ist, dass die Ergebnisse darauf ausgelegt sind, an Claude Code zur echten Umsetzung übergeben zu werden.",
		"p.phase1b": "Ich verbrachte den ersten Teil von Tag eins darin. Ich sagte Claude Design, wer der Kunde war, ein rumänischer Elternteil, der ein personalisiertes Malbuch aus Fotos seines Kindes möchte, und sah zu, wie es eine echte, anklickbare Landingpage auf Rumänisch produzierte: Hero, Vorher/Nachher, Preisstufen, FAQ, Footer. Ich verfeinerte das Layout, straffte den Text, wählte die Farbpalette und passte die Abstände an. Am Ende hatte ich eine Landingpage, die ich mich geschämt hätte, in derselben Zeit von Hand zu bauen.",
		"p.phase1c": "Am Ende dieser Sitzung hatte ich keine einseitige Spezifikation. Ich hatte einen funktionierenden, polierten, meinungsstarken Frontend-Prototyp, einschließlich der visuellen Identität der Marke, der in Claude Design saß und bereit war, übergeben zu werden.",
		"h.phase2": "Phase 2: Übergabe an Claude Code",
		"p.phase2a": "Dann übergab ich es an <strong>Claude Code</strong> und ließ es den Rest bauen: den Claude-Design-Prototyp in ein echtes Vite + React-Projekt überführen, den Foto-Upload verdrahten, das Hono-Backend bauen, Vertex AI Gemini für die Bildgenerierung integrieren, Stripe Checkout anbinden, Cloud Run, Firestore, GCS-Lifecycle-Regeln, den Telegram-Benachrichtigungsbot, das GitHub-Actions-Deployment auf Cloudflare Pages und den Analytics-Einwilligungsfluss konfigurieren.",
		"p.phase2b": "Von da an war es eine Schleife. Ich beschrieb das nächste Verhaltenssegment, Claude Code setzte es um, ich testete es, wir iterierten. Der Aufbau verlief als eine Abfolge gut abgegrenzter Tickets, jedes klein genug, um es vor dem Weitermachen zu verifizieren. Am Ende von Tag drei hatte ich ein deployedes, zahlungsfähiges Produkt auf einer eigenen Domain.",
		"p.phase2c": "Die Übergabe selbst war der Teil, von dem ich nicht erwartet hatte, dass er mir so viel Freude bereitet. Claude Design produzierte die Oberfläche, die der Kunde sieht, Claude Code produzierte alles dahinter, und die beiden Tools fügten sich zu einem einzigen kontinuierlichen Workflow zusammen, statt zu zwei separaten, an den Nähten zusammengeklebten Produkten.",
		"h.stack": "Der Stack",
		"p.stack1": "Nichts hier ist neuartig. Ich habe überall, wo ich konnte, Managed Services gewählt.",
		"li.frontend": "<strong>Frontend</strong>: Vite + React 18, deployed auf <strong>Cloudflare Pages</strong> mit Auto-Deploy von GitHub bei jedem Push auf <code>main</code>. Null Infrastruktur zu verwalten, Pushes gehen in unter einer Minute live.",
		"li.backend": "<strong>Backend</strong>: <strong>Hono</strong> auf Node 20, TypeScript mit aktiviertem Strict Mode, deployed auf <strong>Google Cloud Run</strong> in der Region <code>europe-west3</code> (Frankfurt). Nah an den rumänischen Nutzern, skaliert auf null, kostet fast nichts, solange der Traffic klein ist.",
		"li.database": "<strong>Datenbank</strong>: <strong>Firestore</strong>. Eine Collection pro logischem Typ. Keine Migrationen, keine Schema-Dateien, kein DB-Cluster zu betreiben.",
		"li.storage": "<strong>Storage</strong>: <strong>Google Cloud Storage</strong>. Zwei Buckets, einer für eingehende Nutzer-Uploads mit einer strikten 72-Stunden-TTL, einer für fertige Bestellungen.",
		"li.imagegen": "<strong>Bildgenerierung</strong>: <strong>Vertex AI Gemini</strong> (das neueste Image-Preview-Modell) als primäre Pipeline, mit einem OpenAI-Bildmodell als Fallback für Ausfallsicherheit.",
		"li.payments": "<strong>Zahlungen</strong>: <strong>Stripe Checkout</strong>. Kartendaten berühren niemals meine Server. Stripe verwaltet die gesamte Zahlungsoberfläche, und ich erhalte lediglich einen Webhook, der mir mitteilt, dass eine Bestellung bezahlt ist.",
		"li.notifications": "<strong>Benachrichtigungen</strong>: ein Telegram-Bot pingt mein Handy an, wann immer etwas Interessantes passiert, etwa wenn eine Bestellung aufgegeben wird, eine Generierung abgeschlossen ist oder ein Webhook auslöst. Es funktioniert als super-einfaches Ops-Dashboard.",
		"li.analytics": "<strong>Analytics</strong>: Cloudflare Web Analytics (cookielos, DSGVO-freundlich), mit Meta Pixel, CAPI und GA4, die hinter einem Consent-Mode-v2-Cookie-Banner vorbereitet sind, für den Fall, dass der Traffic es rechtfertigt.",
		"p.stack2": "Keine dieser Entscheidungen ist clever. Sie sind bewusst langweilig, denn langweilige Infrastruktur ist die Art, die mich in Ruhe lässt.",
		"h.security": "Sicherheit, weil das Produkt Fotos von Kindern verarbeitet",
		"p.security1": "Bei diesem Teil möchte ich explizit sein. Der zentrale Anwendungsfall für Crayo sind Eltern, die Fotos ihrer Kinder hochladen. Manche dieser Fotos sind Familienerinnerungen, die niemand sonst jemals sehen sollte. Ich habe das von der allerersten Design-Konversation an als harte Anforderung behandelt, nicht als ein Feature, das ich später hinzufügen würde.",
		"p.security2": "So sieht das konkret aus:",
		"li.sec.payments": "<strong>Zahlungen laufen vollständig außerhalb der Plattform.</strong> Der gesamte Checkout findet auf Stripe statt. Kartennummern, Rechnungsdaten, CVV. Nichts davon berührt jemals einen Crayo-Server, ein Log oder eine Datenbank. Ich kann keine Daten leaken, die ich nie hatte.",
		"li.sec.autodelete": "<strong>Hochgeladene Fotos löschen sich automatisch.</strong> Nutzer-Uploads landen in einem Cloud-Storage-Bucket mit einer <strong>72-Stunden-Lifecycle-Regel</strong>. Nach diesem Zeitfenster löscht Google sie selbst. Es ist keine Admin-Aktion erforderlich, und ich kann es nicht vergessen.",
		"li.sec.notrain": "<strong>Fotos werden nicht zum Trainieren von irgendetwas verwendet.</strong> Die Vertex-AI-Bild-Endpoints, die ich verwende, sind keine Trainings-Pipelines. Ein Foto eines Kindes geht hinein, eine Malseite kommt heraus, und das Quellbild wird auf dem 72-Stunden-Timer verworfen.",
		"li.sec.secrets": "<strong>Secrets liegen im Google Secret Manager.</strong> Stripe-Schlüssel, API-Credentials, Webhook-Signing-Secrets. Keines davon ist im Repo, keines in irgendwo committeten Umgebungsdateien, und der Cloud-Run-Dienst bindet sie zur Laufzeit über <code>--set-secrets</code> ein.",
		"li.sec.https": "<strong>Nur HTTPS, überall.</strong> Cloudflare vor der statischen Website, von Google verwaltete Zertifikate vor Cloud Run.",
		"li.sec.gdpr": "<strong>DSGVO-Einwilligung vor jeglichem Tracking.</strong> Das Einwilligungsbanner blockiert Meta Pixel, GA4 und alle nicht-essenziellen Tags, bis der Nutzer zustimmt. Cloudflare Web Analytics ist das Einzige, das ohne Einwilligung läuft, weil es cookielos und aggregiert ist.",
		"p.security3": "Nichts davon ist exotisch. Es ist die Version von \"standardmäßig sicher\", mit der ich leben kann, angesichts dessen, was die Leute hochladen.",
		"h.headline": "Warum die drei Tage die Schlagzeile sind, nicht die Technik",
		"p.headline1": "Das Interessante an Crayo ist nicht der Stack. Der Stack ist, was auch immer der Stack ist. Das Interessante ist, dass die Kosten dafür, von \"Ich habe beim Morgenkaffee eine Idee\" zu \"ein Fremder hat mich dafür bezahlt\" zu gelangen, kollabiert sind.",
		"p.headline2": "Vor ein paar Jahren wäre dieser Aufbau ein mehrwöchiges Projekt gewesen. Ich hätte Tage mit Auth verbracht, Tage mit Bildgenerierungs-Pipelines, Tage damit, mit einer Zahlungsintegration zu kämpfen. Heute hat sich der Engpass vollständig vom Tippen von Code weg verschoben, hin zu den Dingen, die KI nicht für mich tun kann: zu entscheiden, was ich baue, mit echten Nutzern zu sprechen, den Markt zu verstehen und das rechtliche Risiko einzugehen, ein Geschäft in die Welt zu setzen.",
		"h.next": "Was als Nächstes kommt",
		"p.next1": "Crayo steht am Anfang seines Lebens. Gerade bin ich in der Akquisephase: Ich fahre eine kleine Meta-Ads-Kampagne, beobachte die Analytics, mache A/B-Tests an der Landingpage und lese jedes Feedback, das ich von echten Kunden bekomme. Der nächste Meilenstein ist kein ausgefeilteres Feature. Es ist der zehnte zahlende Fremde und dann der hundertste.",
		"p.next2": "Um diese Schleife zu beschleunigen, habe ich eine Claude-Routine eingerichtet, die jeden Tag läuft. Sie zieht die Anzeigenleistung des Vortags aus Meta, entwirft neue Creatives und passt entweder die Kampagne an oder nimmt Änderungen an der crayo.ro-Website vor, basierend auf dem, was sie sieht. Ich bin ehrlich gespannt, wie das läuft.",
		"p.next3": "Diese erste 2-Euro-Stripe-Benachrichtigung von einem Fremden ist immer noch der Teil, an den ich ständig denken muss. Sie hat das Ganze real wirken lassen.",
		"p.next4": "Wenn du Kinder, einen Hund oder eine Erinnerung hast, die du in ein Malbuch verwandeln möchtest, ist <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a> live. Und wenn du auf einer Idee sitzt und dich fragst, ob du sie launchen kannst, dann sind mit den richtigen Tools drei Tage wahrscheinlich genug.",
		"h.keepreading": "Weiterlesen",
		"p.keepreading": "Mach weiter mit <a href=\"/blog/\">dem Blog-Index</a>, lies, wie wir <a href=\"/blog/3d-printer-caricature.html\">einen 3D-Drucker in einen Karikaturisten verwandelt haben</a>, oder <a href=\"/blog/ai-powered-f1-leaderboard.html\">wie ich mit KI ein F1-Leaderboard gebaut habe</a>.",
		"cta.home": "Zurück zur Startseite",
		"cta.blog": "Mehr Blogbeiträge",
		"cta.crayo": "Crayo besuchen"
	},
	"es": {
		"meta.title": "Construyendo Crayo en 3 días: de Claude Design al primer desconocido que paga - Voic Andrei",
		"meta.description": "Cómo construí Crayo, un SaaS que convierte fotos en PDF de libros para colorear generados con IA, en tres días. De un prototipo en Claude Design a un producto en vivo respaldado por Stripe, y mis primeros 2 euros de un completo desconocido.",
		"title": "Construyendo Crayo en 3 días: de Claude Design al primer desconocido que paga",
		"date": "<time datetime=\"2026-05-17\">17 de mayo de 2026</time>",
		"h.euros": "Dos euros de un desconocido",
		"p.euros1": "Unos días después de lanzar discretamente <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a>, mi teléfono vibró con una notificación de Stripe. Un completo desconocido, alguien a quien nunca había conocido ni a quien le había vendido nada directamente, me había pagado unos 2 euros por un libro para colorear personalizado hecho con sus propias fotos.",
		"p.euros2": "Es una cifra minúscula, pero me hizo genuinamente feliz. Alguien miró mi producto, decidió que valía su dinero y pagó por él. Esa es la parte que me importaba.",
		"h.what": "Qué es Crayo",
		"p.what1": "<strong>Crayo</strong> es un pequeño SaaS en rumano que convierte cualquier foto en un PDF de libro para colorear personalizado y generado con IA. Subes fotos de tu hijo, de tu perro, de un momento familiar, lo que quieras. Pagas a través de Stripe. Obtienes un PDF imprimible con páginas para colorear limpias y aptas para niños, generadas a partir de tus imágenes. Todo el producto está en rumano, con precios en lei, dirigido a padres rumanos.",
		"p.what2": "El precio hoy es deliberadamente simple: hasta 20 fotos por 9,90 lei. No estoy optimizando el margen en esta etapa. Estoy optimizando el precio más bajo posible que aún requiera una transacción real en Stripe, para que el primer cliente sea una señal comercial auténtica y no un favor de alguien que me conoce.",
		"h.why": "Por qué lo construí en primer lugar",
		"p.why1": "Sinceramente, empecé Crayo para ver qué podía hacer Claude Design. Anthropic Labs lo lanzó en abril de 2026 y yo quería un proyecto real, de principio a fin, para ponerlo a prueba. El plan era pasar una tarde prototipando la idea, ver el resultado y seguir adelante.",
		"p.why2": "Una vez que vi lo que salió de esa tarde, decidí lanzarlo en su lugar. También me puse un reto personal: construir un SaaS que realmente consiguiera al menos un cliente que pagara desde fuera de mi red. No amigos, no familia, no compañeros generosos. Un desconocido real pagando dinero real por un producto real. Ese reto es lo que me hizo ir más allá del prototipo y lanzarlo de verdad.",
		"h.threedays": "Tres días, de principio a fin",
		"p.threedays1": "Toda la construcción técnica tomó tres días. Dominio, frontend, backend, pipeline de generación de imágenes, pagos, despliegue, analítica. El plazo no se debe a que yo sea rápido. El plazo es el flujo de trabajo.",
		"h.phase1": "Fase 1: Prototipado en Claude Design",
		"p.phase1a": "Empecé dentro de <a href=\"https://www.anthropic.com/news/claude-design-anthropic-labs\" target=\"_blank\">Claude Design</a>, la herramienta de prototipado visual que Anthropic Labs lanzó en abril de 2026. La premisa es simple. Describes un producto en lenguaje natural y Claude construye una primera versión de la interfaz. Luego refinas mediante conversación, comentarios en línea, ediciones directas y sliders personalizados. Funciona con Claude Opus 4.7 y, lo que es crucial, los resultados están diseñados para ser entregados a Claude Code para una implementación real.",
		"p.phase1b": "Pasé la primera parte del día uno ahí dentro. Le dije a Claude Design quién era el cliente, un padre rumano que quiere un libro para colorear personalizado hecho con fotos de su hijo, y lo vi producir una landing page real y clicable en rumano: hero, antes/después, niveles de precios, FAQ, footer. Refiné el diseño, ajusté el texto, elegí la paleta y ajusté el espaciado. Terminé con una landing page que me habría avergonzado construir a mano en el mismo tiempo.",
		"p.phase1c": "Al final de esa sesión no tenía una especificación de una página. Tenía un prototipo de frontend funcional, pulido y con criterio, incluyendo la identidad visual de la marca, alojado en Claude Design y listo para ser entregado.",
		"h.phase2": "Fase 2: Entrega a Claude Code",
		"p.phase2a": "Luego se lo entregué a <strong>Claude Code</strong> y dejé que construyera el resto: llevar el prototipo de Claude Design a un proyecto real de Vite + React, conectar la subida de fotos, construir el backend de Hono, integrar Vertex AI Gemini para la generación de imágenes, conectar Stripe Checkout, configurar Cloud Run, Firestore, las reglas de ciclo de vida de GCS, el bot de notificaciones de Telegram, el despliegue con GitHub Actions a Cloudflare Pages y el flujo de consentimiento de analítica.",
		"p.phase2b": "A partir de ahí fue un bucle. Describía la siguiente porción de comportamiento, Claude Code la implementaba, yo la probaba, iterábamos. La construcción avanzó como una secuencia de tickets bien acotados, cada uno lo bastante pequeño como para verificarlo antes de seguir. Al final del día tres tenía un producto desplegado, capaz de aceptar pagos, en un dominio personalizado.",
		"p.phase2c": "La entrega en sí fue la parte que no esperaba disfrutar tanto como lo hice. Claude Design produjo la superficie que ve el cliente, Claude Code produjo todo lo que hay detrás, y las dos herramientas encajaron como un único flujo de trabajo continuo en lugar de dos productos separados pegados por las costuras.",
		"h.stack": "El stack",
		"p.stack1": "Nada de esto es novedoso. Elegí servicios gestionados donde pude.",
		"li.frontend": "<strong>Frontend</strong>: Vite + React 18, desplegado en <strong>Cloudflare Pages</strong> con auto-despliegue desde GitHub en cada push a <code>main</code>. Cero infraestructura que gestionar, los pushes pasan a producción en menos de un minuto.",
		"li.backend": "<strong>Backend</strong>: <strong>Hono</strong> sobre Node 20, TypeScript con strict mode activado, desplegado en <strong>Google Cloud Run</strong> en la región <code>europe-west3</code> (Frankfurt). Cerca de los usuarios rumanos, escala a cero, cuesta casi nada mientras el tráfico es pequeño.",
		"li.database": "<strong>Base de datos</strong>: <strong>Firestore</strong>. Una colección por tipo lógico. Sin migraciones, sin archivos de esquema, sin clúster de base de datos que operar.",
		"li.storage": "<strong>Almacenamiento</strong>: <strong>Google Cloud Storage</strong>. Dos buckets, uno para las subidas entrantes de los usuarios con un TTL estricto de 72 horas, y otro para los pedidos finalizados.",
		"li.imagegen": "<strong>Generación de imágenes</strong>: <strong>Vertex AI Gemini</strong> (el último modelo image-preview) como pipeline principal, con un modelo de imagen de OpenAI conectado como respaldo para mayor resiliencia.",
		"li.payments": "<strong>Pagos</strong>: <strong>Stripe Checkout</strong>. Los datos de la tarjeta nunca tocan mis servidores. Stripe gestiona toda la superficie de pago y yo solo recibo un webhook que me dice que un pedido está pagado.",
		"li.notifications": "<strong>Notificaciones</strong>: un bot de Telegram avisa a mi teléfono cada vez que ocurre algo interesante, como que se realiza un pedido, que termina una generación o que se dispara un webhook. Funciona como un panel de operaciones extremadamente simple.",
		"li.analytics": "<strong>Analítica</strong>: Cloudflare Web Analytics (sin cookies, compatible con el RGPD), con Meta Pixel, CAPI y GA4 preparados detrás de un banner de cookies con Consent Mode v2 para cuando el tráfico lo justifique.",
		"p.stack2": "Ninguna de estas elecciones es ingeniosa. Son deliberadamente aburridas, porque la infraestructura aburrida es la clase que me deja en paz.",
		"h.security": "Seguridad, porque el producto procesa fotos de niños",
		"p.security1": "Sobre esta parte quiero ser explícito. El caso de uso central de Crayo son padres subiendo fotos de sus hijos. Algunas de esas fotos son recuerdos familiares que nadie más debería ver jamás. Lo traté como un requisito estricto desde la primera conversación de diseño, no como una función que añadiría más tarde.",
		"p.security2": "Así es como se ve esto en concreto:",
		"li.sec.payments": "<strong>Los pagos están completamente fuera de la plataforma.</strong> Todo el checkout ocurre en Stripe. Números de tarjeta, datos de facturación, CVV. Nada de eso toca jamás un servidor, log o base de datos de Crayo. No puedo filtrar datos que nunca tuve.",
		"li.sec.autodelete": "<strong>Las fotos subidas se eliminan automáticamente.</strong> Las subidas de los usuarios aterrizan en un bucket de Cloud Storage con una <strong>regla de ciclo de vida de 72 horas</strong>. Pasada esa ventana, Google mismo las purga. No se requiere ninguna acción de administración y no hay forma de que se me olvide.",
		"li.sec.notrain": "<strong>Las fotos no se usan para entrenar nada.</strong> Los endpoints de imagen de Vertex AI que uso no son pipelines de entrenamiento. La foto de un niño entra, una página para colorear sale, y la imagen de origen se descarta con el temporizador de 72 horas.",
		"li.sec.secrets": "<strong>Los secretos viven en Google Secret Manager.</strong> Claves de Stripe, credenciales de API, secretos de firma de webhooks. Ninguno está en el repo, ninguno está en archivos de entorno comiteados en ningún sitio, y el servicio de Cloud Run los vincula en tiempo de ejecución mediante <code>--set-secrets</code>.",
		"li.sec.https": "<strong>Solo HTTPS, en todas partes.</strong> Cloudflare delante del sitio estático, certificados gestionados por Google delante de Cloud Run.",
		"li.sec.gdpr": "<strong>Consentimiento RGPD antes de cualquier seguimiento.</strong> El banner de consentimiento bloquea Meta Pixel, GA4 y cualquier etiqueta no esencial hasta que el usuario da su consentimiento. Cloudflare Web Analytics es lo único que se ejecuta sin consentimiento, porque es sin cookies y agregado.",
		"p.security3": "Nada de esto es exótico. Es la versión de \"por defecto, seguro\" con la que puedo vivir dado lo que la gente está subiendo.",
		"h.headline": "Por qué los tres días son el titular, no la tecnología",
		"p.headline1": "Lo interesante de Crayo no es el stack. El stack es lo que sea que sea el stack. Lo interesante es que el coste de pasar de \"tengo una idea con el café de la mañana\" a \"un desconocido me pagó por ella\" se ha desplomado.",
		"p.headline2": "Hace unos años, esta construcción habría sido un proyecto de varias semanas. Habría pasado días con la autenticación, días con los pipelines de generación de imágenes, días peleándome con una integración de pagos. Hoy el cuello de botella se ha desplazado por completo de teclear código a las cosas que la IA no puede hacer por mí: decidir qué construir, hablar con usuarios reales, entender el mercado y asumir el riesgo legal de poner un negocio en el mundo.",
		"h.next": "Qué viene ahora",
		"p.next1": "Crayo está en el comienzo de su vida. Ahora mismo estoy en la fase de adquisición: ejecutando una pequeña campaña de Meta Ads, observando la analítica, haciendo A/B testing en la landing page y leyendo cada pieza de feedback que recibo de clientes reales. El próximo hito no es una función más sofisticada. Es el décimo desconocido que paga, y luego el centésimo.",
		"p.next2": "Para acelerar ese bucle, configuré una rutina de Claude que se ejecuta cada día. Saca el rendimiento de los anuncios del día anterior de Meta, redacta nuevos creativos y o bien ajusta la campaña o hace cambios en el sitio crayo.ro según lo que ve. Tengo genuina curiosidad por ver cómo va.",
		"p.next3": "Esa primera notificación de Stripe de 2 euros de un desconocido sigue siendo la parte en la que no dejo de pensar. Hizo que todo se sintiera real.",
		"p.next4": "Si tienes hijos, un perro o un recuerdo que quieras convertir en un libro para colorear, <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a> está en vivo. Y si estás sentado sobre una idea preguntándote si puedes lanzarla, con las herramientas adecuadas, tres días probablemente sean suficientes.",
		"h.keepreading": "Sigue leyendo",
		"p.keepreading": "Continúa con <a href=\"/blog/\">el índice del blog</a>, lee cómo <a href=\"/blog/3d-printer-caricature.html\">convertimos una impresora 3D en un artista caricaturista</a>, o <a href=\"/blog/ai-powered-f1-leaderboard.html\">cómo construí una tabla de clasificación de F1 con IA</a>.",
		"cta.home": "Volver al inicio",
		"cta.blog": "Más entradas del blog",
		"cta.crayo": "Visitar Crayo"
	},
	"fr": {
		"meta.title": "Construire Crayo en 3 jours : de Claude Design au premier inconnu qui paie - Voic Andrei",
		"meta.description": "Comment j'ai construit Crayo, un SaaS qui transforme des photos en PDF de livres de coloriage générés par IA, en trois jours. D'un prototype Claude Design à un produit en ligne adossé à Stripe, et mes premiers 2 euros d'un parfait inconnu.",
		"title": "Construire Crayo en 3 jours : de Claude Design au premier inconnu qui paie",
		"date": "<time datetime=\"2026-05-17\">17 mai 2026</time>",
		"h.euros": "Deux euros d'un inconnu",
		"p.euros1": "Quelques jours après avoir lancé discrètement <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a>, mon téléphone a vibré avec une notification Stripe. Un parfait inconnu, quelqu'un que je n'avais jamais rencontré ni à qui je n'avais jamais vendu directement, venait de me payer environ 2 euros pour un livre de coloriage personnalisé réalisé à partir de ses propres photos.",
		"p.euros2": "C'est un chiffre minuscule, mais cela m'a rendu sincèrement heureux. Quelqu'un a regardé mon produit, a décidé qu'il valait son argent et a payé pour. C'est la partie qui comptait pour moi.",
		"h.what": "Ce qu'est Crayo",
		"p.what1": "<strong>Crayo</strong> est un petit SaaS en langue roumaine qui transforme n'importe quelle photo en un PDF de livre de coloriage personnalisé, généré par IA. Vous téléchargez des photos de votre enfant, de votre chien, d'un moment en famille, tout ce que vous voulez. Vous payez via Stripe. Vous obtenez un PDF imprimable de pages de coloriage nettes et adaptées aux enfants, générées à partir de vos images. Tout le produit est en roumain, avec des prix en lei, et s'adresse aux parents roumains.",
		"p.what2": "Le prix aujourd'hui est volontairement simple : jusqu'à 20 photos pour 9,90 lei. Je n'optimise pas la marge à ce stade. J'optimise le prix le plus bas possible qui nécessite tout de même une vraie transaction Stripe, afin que le premier client soit un véritable signal commercial et non une faveur de la part de quelqu'un qui me connaît.",
		"h.why": "Pourquoi je l'ai construit, au fond",
		"p.why1": "Honnêtement, j'ai commencé Crayo pour voir ce que Claude Design pouvait faire. Anthropic Labs l'a publié en avril 2026 et je voulais un vrai projet de bout en bout pour le mettre à l'épreuve. Le plan était de passer un après-midi à prototyper l'idée, à regarder le résultat, puis à passer à autre chose.",
		"p.why2": "Une fois que j'ai vu ce qui était sorti de cet après-midi-là, j'ai décidé de le lancer à la place. Je me suis aussi lancé un défi personnel : construire un SaaS qui obtienne réellement au moins un client payant en dehors de mon réseau. Pas des amis, pas la famille, pas des collègues généreux. Un véritable inconnu payant de l'argent réel pour un vrai produit. C'est ce défi qui m'a poussé à aller au-delà du prototype et à le lancer pour de bon.",
		"h.threedays": "Trois jours, de bout en bout",
		"p.threedays1": "Toute la construction technique a pris trois jours. Domaine, frontend, backend, pipeline de génération d'images, paiements, déploiement, analytics. Ce calendrier ne tient pas à ma rapidité. Ce calendrier, c'est le flux de travail.",
		"h.phase1": "Phase 1 : Prototypage dans Claude Design",
		"p.phase1a": "J'ai commencé dans <a href=\"https://www.anthropic.com/news/claude-design-anthropic-labs\" target=\"_blank\">Claude Design</a>, l'outil de prototypage visuel qu'Anthropic Labs a publié en avril 2026. Le principe est simple. Vous décrivez un produit en langage naturel et Claude construit une première version de l'interface. Vous affinez ensuite par la conversation, des commentaires en ligne, des modifications directes et des curseurs personnalisés. Il est propulsé par Claude Opus 4.7 et, surtout, les résultats sont conçus pour être transmis à Claude Code en vue d'une implémentation réelle.",
		"p.phase1b": "J'ai passé la première partie du jour un là-dedans. J'ai dit à Claude Design qui était le client, un parent roumain qui veut un livre de coloriage personnalisé réalisé à partir de photos de son enfant, et je l'ai regardé produire une véritable landing page cliquable en roumain : hero, avant/après, niveaux de prix, FAQ, footer. J'ai affiné la mise en page, resserré le texte, choisi la palette et ajusté les espacements. J'ai fini avec une landing page que j'aurais été gêné de construire à la main dans le même laps de temps.",
		"p.phase1c": "À la fin de cette session, je n'avais pas une spécification d'une page. J'avais un prototype frontend fonctionnel, soigné et affirmé, y compris l'identité visuelle de la marque, posé dans Claude Design et prêt à être transmis.",
		"h.phase2": "Phase 2 : Transmission à Claude Code",
		"p.phase2a": "Puis je l'ai transmis à <strong>Claude Code</strong> et je l'ai laissé construire le reste : importer le prototype Claude Design dans un véritable projet Vite + React, câbler le téléchargement de photos, construire le backend Hono, intégrer Vertex AI Gemini pour la génération d'images, brancher Stripe Checkout, configurer Cloud Run, Firestore, les règles de cycle de vie GCS, le bot de notifications Telegram, le déploiement via GitHub Actions vers Cloudflare Pages et le flux de consentement analytics.",
		"p.phase2b": "À partir de là, ce fut une boucle. Je décrivais la prochaine tranche de comportement, Claude Code l'implémentait, je la testais, on itérait. La construction s'est déroulée comme une séquence de tickets bien délimités, chacun assez petit pour être vérifié avant de passer à la suite. À la fin du troisième jour, j'avais un produit déployé, capable d'accepter des paiements, sur un domaine personnalisé.",
		"p.phase2c": "La transmission elle-même a été la partie que je ne m'attendais pas à apprécier autant. Claude Design a produit la surface que voit le client, Claude Code a produit tout ce qui se trouve derrière, et les deux outils se sont assemblés en un seul flux de travail continu plutôt qu'en deux produits distincts collés aux coutures.",
		"h.stack": "La stack",
		"p.stack1": "Rien ici n'est nouveau. J'ai choisi des services managés partout où je le pouvais.",
		"li.frontend": "<strong>Frontend</strong> : Vite + React 18, déployé sur <strong>Cloudflare Pages</strong> avec auto-déploiement depuis GitHub à chaque push sur <code>main</code>. Zéro infrastructure à gérer, les pushes passent en ligne en moins d'une minute.",
		"li.backend": "<strong>Backend</strong> : <strong>Hono</strong> sur Node 20, TypeScript avec strict mode activé, déployé sur <strong>Google Cloud Run</strong> dans la région <code>europe-west3</code> (Francfort). Proche des utilisateurs roumains, scale jusqu'à zéro, ne coûte presque rien tant que le trafic est faible.",
		"li.database": "<strong>Base de données</strong> : <strong>Firestore</strong>. Une collection par type logique. Pas de migrations, pas de fichiers de schéma, pas de cluster de base de données à exploiter.",
		"li.storage": "<strong>Stockage</strong> : <strong>Google Cloud Storage</strong>. Deux buckets, un pour les téléchargements entrants des utilisateurs avec un TTL strict de 72 heures, un pour les commandes terminées.",
		"li.imagegen": "<strong>Génération d'images</strong> : <strong>Vertex AI Gemini</strong> (le dernier modèle image-preview) comme pipeline principal, avec un modèle d'image OpenAI branché en repli pour la résilience.",
		"li.payments": "<strong>Paiements</strong> : <strong>Stripe Checkout</strong>. Les données de carte ne touchent jamais mes serveurs. Stripe gère toute la surface de paiement et je reçois simplement un webhook m'indiquant qu'une commande est payée.",
		"li.notifications": "<strong>Notifications</strong> : un bot Telegram fait sonner mon téléphone chaque fois qu'il se passe quelque chose d'intéressant, comme une commande passée, une génération terminée ou un webhook déclenché. Il fonctionne comme un tableau de bord d'exploitation ultra-simple.",
		"li.analytics": "<strong>Analytics</strong> : Cloudflare Web Analytics (sans cookies, compatible RGPD), avec Meta Pixel, CAPI et GA4 préparés derrière une bannière de cookies en Consent Mode v2 pour quand le trafic le justifiera.",
		"p.stack2": "Aucun de ces choix n'est astucieux. Ils sont délibérément ennuyeux, parce qu'une infrastructure ennuyeuse est celle qui me laisse tranquille.",
		"h.security": "La sécurité, parce que le produit traite des photos d'enfants",
		"p.security1": "Sur cette partie, je veux être explicite. Le cas d'usage central de Crayo, ce sont des parents qui téléchargent des photos de leurs enfants. Certaines de ces photos sont des souvenirs de famille que personne d'autre ne devrait jamais voir. J'ai traité cela comme une exigence ferme dès la toute première conversation de design, et non comme une fonctionnalité que j'ajouterais plus tard.",
		"p.security2": "Concrètement, voici à quoi cela ressemble :",
		"li.sec.payments": "<strong>Les paiements sont entièrement hors plateforme.</strong> Tout le checkout se passe sur Stripe. Numéros de carte, détails de facturation, CVV. Rien de tout cela ne touche jamais un serveur, un log ou une base de données Crayo. Je ne peux pas faire fuiter des données que je n'ai jamais eues.",
		"li.sec.autodelete": "<strong>Les photos téléchargées s'auto-suppriment.</strong> Les téléchargements des utilisateurs atterrissent dans un bucket Cloud Storage doté d'une <strong>règle de cycle de vie de 72 heures</strong>. Passé ce délai, Google les purge lui-même. Aucune action d'administration n'est requise et il n'y a aucun moyen pour moi d'oublier.",
		"li.sec.notrain": "<strong>Les photos ne servent à entraîner quoi que ce soit.</strong> Les endpoints d'image Vertex AI que j'utilise ne sont pas des pipelines d'entraînement. La photo d'un enfant entre, une page de coloriage sort, et l'image source est supprimée selon le minuteur de 72 heures.",
		"li.sec.secrets": "<strong>Les secrets résident dans Google Secret Manager.</strong> Clés Stripe, identifiants d'API, secrets de signature de webhooks. Aucun n'est dans le dépôt, aucun n'est dans des fichiers d'environnement commités où que ce soit, et le service Cloud Run les lie au runtime via <code>--set-secrets</code>.",
		"li.sec.https": "<strong>HTTPS uniquement, partout.</strong> Cloudflare devant le site statique, certificats gérés par Google devant Cloud Run.",
		"li.sec.gdpr": "<strong>Consentement RGPD avant tout tracking.</strong> La bannière de consentement bloque Meta Pixel, GA4 et tout tag non essentiel jusqu'à ce que l'utilisateur donne son accord. Cloudflare Web Analytics est la seule chose qui s'exécute sans consentement, parce qu'elle est sans cookies et agrégée.",
		"p.security3": "Rien de tout cela n'est exotique. C'est la version du \"sûr par défaut\" avec laquelle je peux vivre, compte tenu de ce que les gens téléchargent.",
		"h.headline": "Pourquoi les trois jours sont le titre, pas la technique",
		"p.headline1": "Ce qui est intéressant avec Crayo, ce n'est pas la stack. La stack est ce qu'elle est. Ce qui est intéressant, c'est que le coût pour passer de \"j'ai une idée au café du matin\" à \"un inconnu m'a payé pour ça\" s'est effondré.",
		"p.headline2": "Il y a quelques années, cette construction aurait été un projet de plusieurs semaines. J'aurais passé des jours sur l'authentification, des jours sur les pipelines de génération d'images, des jours à me battre avec une intégration de paiement. Aujourd'hui, le goulot d'étranglement s'est entièrement déplacé de la frappe de code vers les choses que l'IA ne peut pas faire à ma place : décider quoi construire, parler à de vrais utilisateurs, comprendre le marché et prendre le risque juridique de mettre une entreprise au monde.",
		"h.next": "La suite",
		"p.next1": "Crayo en est au début de sa vie. En ce moment, je suis en phase d'acquisition : je fais tourner une petite campagne Meta Ads, je surveille l'analytics, je fais de l'A/B testing sur la landing page et je lis chaque retour que je reçois de vrais clients. Le prochain jalon n'est pas une fonctionnalité plus sophistiquée. C'est le dixième inconnu qui paie, puis le centième.",
		"p.next2": "Pour accélérer cette boucle, j'ai mis en place une routine Claude qui s'exécute chaque jour. Elle récupère les performances des publicités de la veille depuis Meta, rédige de nouveaux visuels et soit ajuste la campagne, soit apporte des modifications au site crayo.ro en fonction de ce qu'elle observe. Je suis sincèrement curieux de voir comment cela évolue.",
		"p.next3": "Cette première notification Stripe de 2 euros venant d'un inconnu reste la partie à laquelle je ne cesse de penser. Elle a rendu tout cela réel.",
		"p.next4": "Si vous avez des enfants, un chien ou un souvenir que vous voulez transformer en livre de coloriage, <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a> est en ligne. Et si vous êtes assis sur une idée en vous demandant si vous pouvez la lancer, avec les bons outils, trois jours suffisent probablement.",
		"h.keepreading": "Continuez votre lecture",
		"p.keepreading": "Continuez avec <a href=\"/blog/\">l'index du blog</a>, lisez comment nous avons <a href=\"/blog/3d-printer-caricature.html\">transformé une imprimante 3D en caricaturiste</a>, ou <a href=\"/blog/ai-powered-f1-leaderboard.html\">comment j'ai construit un classement F1 avec l'IA</a>.",
		"cta.home": "Retour à l'accueil",
		"cta.blog": "Plus d'articles de blog",
		"cta.crayo": "Visiter Crayo"
	},
	"zh": {
		"meta.title": "三天打造 Crayo：从 Claude Design 到第一位付费的陌生人 - Voic Andrei",
		"meta.description": "我如何在三天内打造 Crayo——一个把照片变成 AI 生成涂色书 PDF 的 SaaS。从一个 Claude Design 原型到一个由 Stripe 支撑的上线产品，以及我从一位完全陌生的人那里赚到的头 2 欧元。",
		"title": "三天打造 Crayo：从 Claude Design 到第一位付费的陌生人",
		"date": "<time datetime=\"2026-05-17\">2026 年 5 月 17 日</time>",
		"h.euros": "来自陌生人的两欧元",
		"p.euros1": "在我悄悄上线 <a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a> 几天后，我的手机响起了一条 Stripe 通知。一个完全陌生的人，一个我从未见过、也从未直接向其推销过的人，为一本用他自己照片制作的个性化涂色书付给了我大约 2 欧元。",
		"p.euros2": "这是一个微不足道的数字，但它让我由衷地感到高兴。有人看了我的产品，认定它值这个钱，并为之付了款。这才是我在意的部分。",
		"h.what": "Crayo 是什么",
		"p.what1": "<strong>Crayo</strong> 是一个小型的罗马尼亚语 SaaS，能把任何照片变成一本个性化、由 AI 生成的涂色书 PDF。你上传自己孩子、自己的狗、某个家庭瞬间的照片，任何你想要的内容。你通过 Stripe 付款。你会得到一份可打印的 PDF，里面是从你的图片生成的、干净、适合孩子的涂色页。整个产品都是罗马尼亚语，以列伊定价，面向罗马尼亚的父母。",
		"p.what2": "如今的定价刻意保持简单：最多 20 张照片收 9.90 列伊。在这个阶段我并不追求利润率。我追求的是仍然需要一笔真实 Stripe 交易的尽可能低的价格，这样第一位客户就是一个真正的商业信号，而不是某个认识我的人给的人情。",
		"h.why": "我究竟为什么要做它",
		"p.why1": "老实说，我开始做 Crayo 是为了看看 Claude Design 能做什么。Anthropic Labs 在 2026 年 4 月发布了它，而我想要一个真实的、端到端的项目来好好检验它。原本的计划是花一个下午把这个想法做成原型，看看结果，然后就此打住。",
		"p.why2": "一旦我看到那个下午做出来的东西，我反而决定把它上线。我还给自己定了一个个人挑战：做一个真正能从我的人脉圈之外获得至少一位付费客户的 SaaS。不是朋友，不是家人，不是慷慨的同事。一个真正的陌生人为一个真正的产品付出真金白银。正是这个挑战让我越过原型，真正把它上线。",
		"h.threedays": "三天，从头到尾",
		"p.threedays1": "整个技术构建花了三天。域名、前端、后端、图像生成管线、支付、部署、分析。这个时间线不是因为我快。这个时间线是工作流程。",
		"h.phase1": "第一阶段：在 Claude Design 中做原型",
		"p.phase1a": "我从 <a href=\"https://www.anthropic.com/news/claude-design-anthropic-labs\" target=\"_blank\">Claude Design</a> 开始，这是 Anthropic Labs 在 2026 年 4 月发布的可视化原型工具。前提很简单。你用自然语言描述一个产品，Claude 就会构建出界面的第一个版本。然后你通过对话、内联评论、直接编辑和自定义滑块来精修。它由 Claude Opus 4.7 驱动，而且关键在于，其输出被设计为可以交接给 Claude Code 进行真正的实现。",
		"p.phase1b": "我在里面度过了第一天的头一大段时间。我告诉 Claude Design 客户是谁——一位想要用孩子照片制作个性化涂色书的罗马尼亚父母，然后看着它生成了一个真实的、可点击的罗马尼亚语着陆页：主视觉、前后对比、价格档位、常见问题、页脚。我精修了布局，收紧了文案，挑选了配色，并调整了间距。最终我得到了一个着陆页，如果让我在同样的时间里手工搭建，我会觉得难为情。",
		"p.phase1c": "到那次会话结束时，我手里并不是一份一页纸的规格说明。我有的是一个可用的、精致的、有主见的前端原型，包括品牌的视觉识别，就放在 Claude Design 里，随时可以交接出去。",
		"h.phase2": "第二阶段：交接给 Claude Code",
		"p.phase2a": "然后我把它交给了 <strong>Claude Code</strong>，让它构建剩下的部分：把 Claude Design 原型导入一个真正的 Vite + React 项目、接好照片上传、构建 Hono 后端、集成 Vertex AI Gemini 用于图像生成、接入 Stripe Checkout、配置 Cloud Run、Firestore、GCS 生命周期规则、Telegram 通知机器人、通过 GitHub Actions 部署到 Cloudflare Pages，以及分析同意流程。",
		"p.phase2b": "从那以后就是一个循环。我描述下一小段行为，Claude Code 实现它，我测试它，我们迭代。整个构建以一系列范围明确的工单推进，每一个都小到足以在继续之前完成验证。到第三天结束时，我在一个自定义域名上拥有了一个已部署、可接受付款的产品。",
		"p.phase2c": "交接本身是我没想到会如此享受的部分。Claude Design 生成客户看到的界面，Claude Code 生成它背后的一切，而这两个工具拼合成了一个连续的工作流程，而不是两个在接缝处勉强粘在一起的独立产品。",
		"h.stack": "技术栈",
		"p.stack1": "这里没有任何新奇的东西。我能用托管服务的地方都用了托管服务。",
		"li.frontend": "<strong>前端</strong>：Vite + React 18，部署在 <strong>Cloudflare Pages</strong> 上，每次推送到 <code>main</code> 时从 GitHub 自动部署。零基础设施需要管理，推送会在一分钟内上线。",
		"li.backend": "<strong>后端</strong>：<strong>Hono</strong> 运行在 Node 20 上，TypeScript 开启 strict mode，部署在 <code>europe-west3</code>（法兰克福）区域的 <strong>Google Cloud Run</strong> 上。靠近罗马尼亚用户，可缩容到零，在流量小的时候几乎不花钱。",
		"li.database": "<strong>数据库</strong>：<strong>Firestore</strong>。每种逻辑类型一个集合。没有迁移，没有 schema 文件，没有需要运维的数据库集群。",
		"li.storage": "<strong>存储</strong>：<strong>Google Cloud Storage</strong>。两个存储桶，一个用于传入的用户上传，带有严格的 72 小时 TTL，一个用于已完成的订单。",
		"li.imagegen": "<strong>图像生成</strong>：<strong>Vertex AI Gemini</strong>（最新的 image-preview 模型）作为主管线，并接入一个 OpenAI 图像模型作为后备以保证韧性。",
		"li.payments": "<strong>支付</strong>：<strong>Stripe Checkout</strong>。卡数据从不接触我的服务器。Stripe 处理整个支付环节，我只是收到一个 webhook，告诉我某笔订单已付款。",
		"li.notifications": "<strong>通知</strong>：一个 Telegram 机器人会在发生有趣的事情时给我的手机发提醒，比如有订单下单、一次生成完成或一个 webhook 触发。它充当一个极其简单的运维仪表板。",
		"li.analytics": "<strong>分析</strong>：Cloudflare Web Analytics（无 cookie、对 GDPR 友好），并准备好了 Meta Pixel、CAPI 和 GA4，放在一个 Consent Mode v2 的 cookie 横幅之后，等流量足以证明其合理时再启用。",
		"p.stack2": "这些选择没有一个是聪明的。它们刻意地无聊，因为无聊的基础设施正是那种不来烦我的基础设施。",
		"h.security": "安全，因为这个产品处理的是孩子的照片",
		"p.security1": "这一部分我想说清楚。Crayo 的核心使用场景是父母上传他们孩子的照片。其中一些照片是不该被任何其他人看到的家庭回忆。从第一次设计对话起，我就把它当作一个硬性要求来对待，而不是日后再加的功能。",
		"p.security2": "具体来说是这样的：",
		"li.sec.payments": "<strong>支付完全在平台之外。</strong> 所有结账都在 Stripe 上进行。卡号、账单详情、CVV。这些都从不接触 Crayo 的服务器、日志或数据库。我无法泄露我从未拥有过的数据。",
		"li.sec.autodelete": "<strong>上传的照片自动删除。</strong> 用户上传会落入一个带有 <strong>72 小时生命周期规则</strong>的 Cloud Storage 存储桶。过了那个窗口期，Google 自己就会清除它们。不需要任何管理操作，我也没法忘记。",
		"li.sec.notrain": "<strong>照片不会被用来训练任何东西。</strong> 我使用的 Vertex AI 图像端点不是训练管线。一张孩子的照片进去，一张涂色页出来，源图像在 72 小时计时器上被丢弃。",
		"li.sec.secrets": "<strong>密钥存放在 Google Secret Manager 中。</strong> Stripe 密钥、API 凭证、webhook 签名密钥。它们都不在代码库里，都不在任何地方提交的环境文件里，Cloud Run 服务在运行时通过 <code>--set-secrets</code> 绑定它们。",
		"li.sec.https": "<strong>处处只用 HTTPS。</strong> Cloudflare 挡在静态网站前面，由 Google 管理的证书挡在 Cloud Run 前面。",
		"li.sec.gdpr": "<strong>任何跟踪之前先取得 GDPR 同意。</strong> 同意横幅会拦截 Meta Pixel、GA4 以及任何非必要的标签，直到用户选择同意。Cloudflare Web Analytics 是唯一在没有同意的情况下运行的东西，因为它无 cookie 且只做聚合。",
		"p.security3": "这一切都不稀奇。这是我在人们上传的内容面前能接受的那个版本的「默认安全」。",
		"h.headline": "为什么三天才是头条，而不是技术",
		"p.headline1": "Crayo 有意思的地方不是技术栈。技术栈是什么就是什么。有意思的是，从「我在早晨咖啡时有了个想法」到「一个陌生人为它付了钱」的成本已经崩塌了。",
		"p.headline2": "几年前，这样的构建会是一个数周的项目。我会花好几天在身份验证上，好几天在图像生成管线上，好几天和支付集成搏斗。如今瓶颈已经完全从敲代码转移到了 AI 无法替我做的事情上：决定要做什么、和真实用户交谈、理解市场，以及承担把一门生意推向世界的法律风险。",
		"h.next": "接下来是什么",
		"p.next1": "Crayo 还处在它生命的起点。眼下我正处在获客阶段：投放一个小规模的 Meta Ads 广告系列，观察分析数据，对着陆页做 A/B 测试，并阅读我从真实客户那里收到的每一条反馈。下一个里程碑不是一个更花哨的功能。它是第十位付费的陌生人，然后是第一百位。",
		"p.next2": "为了加速这个循环，我搭建了一个每天运行的 Claude routine。它从 Meta 拉取前一天的广告表现，起草新的创意，并根据所看到的情况，要么调整广告系列，要么对 crayo.ro 网站做出改动。我真心好奇这会如何发展。",
		"p.next3": "那第一条来自陌生人的 2 欧元 Stripe 通知，至今仍是我不停回想的部分。它让这整件事感觉真实了起来。",
		"p.next4": "如果你有孩子、有一只狗，或有一段想变成涂色书的回忆，<a href=\"https://crayo.ro\" target=\"_blank\">crayo.ro</a> 已经上线了。而如果你正抱着一个想法，纠结自己能否把它做出来，那么有了合适的工具，三天大概就够了。",
		"h.keepreading": "继续阅读",
		"p.keepreading": "继续阅读 <a href=\"/blog/\">博客索引</a>，看看我们如何 <a href=\"/blog/3d-printer-caricature.html\">把一台 3D 打印机变成了漫画艺术家</a>，或者 <a href=\"/blog/ai-powered-f1-leaderboard.html\">我如何用 AI 构建了一个 F1 排行榜</a>。",
		"cta.home": "返回首页",
		"cta.blog": "更多博客文章",
		"cta.crayo": "访问 Crayo"
	}
};
